    "key": "safetyculture.pre_start_risk_assessment",
    "name": "Pre Start Risk Assessment",
    "category": "Professional Services",
    "industry": "Professional Services",
    "description": "Explore the Pre Start Risk Assessment template designed to ensure compliance, enhance efficiency and promote safety in your operations.",
    "scoringEnabled": true,
    "source": "library",
