    "name": "Comprehensive Vehicle Service Center Audit Checklist",
    "category": "Transport & logistics",
    "industry": "Transport & logistics",
    "description": "Complete audit framework for vehicle service centers covering site conditions, KPIs, workshop processes, and quality standards. Ensure compliance and operational …",
    "scoringEnabled": true,
